              <div style={{display:'flex',gap:8}}>
                <button style={btn(p.isActive?C.warning:C.success)} onClick={()=>toggle(p._id,p.isActive)}>{p.isActive?'Pause':'Activate'}</button>
                <button style={btn(C.error)} onClick={()=>del(p._id)}>Delete</button>
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
}

